"use client";

import { useEffect, useState } from "react";

export function ProjectGallery({ images, title }: { images: string[]; title: string }) {
  const [active, setActive] = useState<number | null>(null);
  const previous = () => setActive((current) => current === null ? null : (current - 1 + images.length) % images.length);
  const next = () => setActive((current) => current === null ? null : (current + 1) % images.length);
  useEffect(() => {
    if (active === null) return;
    const keydown = (event: KeyboardEvent) => {
      if (event.key === "Escape") setActive(null);
      if (event.key === "ArrowLeft") previous();
      if (event.key === "ArrowRight") next();
    };
    document.body.style.overflow = "hidden";
    window.addEventListener("keydown", keydown);
    return () => { document.body.style.overflow = ""; window.removeEventListener("keydown", keydown); };
  }, [active, images.length]);
  return <>
    <div className="project-gallery-grid">
      {images.map((image, index) => <button type="button" className={index === 0 ? "gallery-featured" : ""} key={`${image}-${index}`} onClick={() => setActive(index)} aria-label={`${title} görsel ${index + 1} büyüt`}><img loading={index > 3 ? "lazy" : "eager"} src={image} alt={`${title} görsel ${index + 1}`} /><span>{String(index + 1).padStart(2, "0")}</span></button>)}
    </div>
    {active !== null && <div className="gallery-lightbox" role="dialog" aria-modal="true" aria-label={`${title} fotoğraf galerisi`} onClick={() => setActive(null)}>
      <button type="button" className="lightbox-close" onClick={() => setActive(null)} aria-label="Galeriyi kapat">×</button>
      {images.length > 1 && <button type="button" className="lightbox-nav lightbox-prev" onClick={(event) => { event.stopPropagation(); previous(); }} aria-label="Önceki görsel">←</button>}
      <div className="lightbox-stage" onClick={(event) => event.stopPropagation()}><img src={images[active]} alt={`${title} büyük görsel ${active + 1}`} /><p>{active + 1} / {images.length}</p></div>
      {images.length > 1 && <button type="button" className="lightbox-nav lightbox-next" onClick={(event) => { event.stopPropagation(); next(); }} aria-label="Sonraki görsel">→</button>}
    </div>}
  </>;
}
